SELECT COUNT(*) 
FROM dismissals 
WHERE dismissal_type = 'lbw';

SELECT name
FROM batsmen
WHERE highest_score = (SELECT MAX(highest_score) FROM batsmen);

SELECT SUM(runs) / matches_played AS average_runs_per_match
FROM batsmen
WHERE batsman_id = 1;

SELECT name, SUM(matches_played) AS total_matches_played
FROM batsmen
GROUP BY name;

SELECT
    SUM(runs) / SUM(matches_played) AS average_runs_per_match
FROM batsmen;
